import React, { useState, useRef, useEffect } from "react";
import "../css/chat.css";
import {
  FaSearch, FaPaperPlane, FaMapMarkerAlt,
  FaCircle, FaArrowLeft, FaHome, FaEllipsisV,
  FaSmile, FaPaperclip, FaPhone, FaVideo,
  FaBed, FaBath, FaExternalLinkAlt, FaTimes,
  FaCheckDouble, FaCheck
} from "react-icons/fa";

/* ─── MOCK CONVERSATIONS ─── */
const CONVERSATIONS = [
  {
    id: 1,
    userName: "Rajesh Kumar",
    userRole: "Owner",
    avatar: "https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=80&q=80",
    online: true,
    lastMsg: "Yes, the apartment is available from April 1st!",
    time: "10:32 AM",
    unread: 2,
    property: {
      id: 9, title: "3BHK Luxury Apartment",
      location: "Saravanampatti", price: 20000,
      beds: 3, baths: 2,
      image: "https://images.unsplash.com/photo-1545324418-cc1a3fa10c00?w=300&q=80"
    },
    messages: [
      { id:1, from:"user",  text:"Hi! Is the 3BHK apartment still available?",           time:"10:20 AM", read:true  },
      { id:2, from:"owner", text:"Hello! Yes it is available. When would you like to visit?", time:"10:22 AM", read:true  },
      { id:3, from:"user",  text:"I'm thinking this weekend. Saturday afternoon?",         time:"10:25 AM", read:true  },
      { id:4, from:"owner", text:"Saturday works perfectly. Around 3 PM?",                 time:"10:28 AM", read:true  },
      { id:5, from:"user",  text:"That's great! What documents do I need to bring?",       time:"10:30 AM", read:true  },
      { id:6, from:"owner", text:"Yes, the apartment is available from April 1st!",        time:"10:32 AM", read:false },
    ]
  },
  {
    id: 2,
    userName: "Priya Raman",
    userRole: "Owner",
    avatar: "https://images.unsplash.com/photo-1494790108377-be9c29b29330?w=80&q=80",
    online: false,
    lastMsg: "The deposit is 2 months rent.",
    time: "Yesterday",
    unread: 0,
    property: {
      id: 4, title: "Women's PG with Meals",
      location: "RS Puram", price: 8500,
      beds: 1, baths: 1,
      image: "https://images.unsplash.com/photo-1522771739844-6a9f6d5f14af?w=300&q=80"
    },
    messages: [
      { id:1, from:"user",  text:"Hello! Is the PG available?",              time:"Yesterday", read:true },
      { id:2, from:"owner", text:"Yes it is! We have 2 rooms available.",    time:"Yesterday", read:true },
      { id:3, from:"user",  text:"What is the security deposit?",            time:"Yesterday", read:true },
      { id:4, from:"owner", text:"The deposit is 2 months rent.",            time:"Yesterday", read:true },
    ]
  },
  {
    id: 3,
    userName: "Suresh Babu",
    userRole: "Owner",
    avatar: "https://images.unsplash.com/photo-1527980965255-d3b416303d12?w=80&q=80",
    online: true,
    lastMsg: "Please come and visit anytime this week.",
    time: "Mar 19",
    unread: 1,
    property: {
      id: 1, title: "2BHK Independent House",
      location: "Peelamedu", price: 15000,
      beds: 2, baths: 1,
      image: "https://images.unsplash.com/photo-1560185127-6ed189bf02f4?w=300&q=80"
    },
    messages: [
      { id:1, from:"user",  text:"Hi, I saw your listing for the 2BHK house.",       time:"Mar 19", read:true },
      { id:2, from:"owner", text:"Hello! Yes, what would you like to know?",          time:"Mar 19", read:true },
      { id:3, from:"user",  text:"Is parking available?",                              time:"Mar 19", read:true },
      { id:4, from:"owner", text:"Please come and visit anytime this week.",           time:"Mar 19", read:false },
    ]
  },
];

const EMOJIS = ["😊","👍","🙏","✅","🏠","💰","📅","🔑","❓","👋"];

export default function Chat() {
  const [conversations, setConversations] = useState(CONVERSATIONS);
  const [activeConv, setActiveConv]       = useState(CONVERSATIONS[0]);
  const [messages, setMessages]           = useState(CONVERSATIONS[0].messages);
  const [inputText, setInputText]         = useState("");
  const [searchQuery, setSearchQuery]     = useState("");
  const [showEmoji, setShowEmoji]         = useState(false);
  const [showProperty, setShowProperty]   = useState(true);
  const [mobileView, setMobileView]       = useState("list"); // "list" | "chat"

  const messagesEndRef = useRef(null);
  const inputRef       = useRef(null);

  /* ── scroll to bottom on new message ── */
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior:"smooth" });
  }, [messages]);

  /* ── select conversation ── */
  const selectConv = (conv) => {
    setActiveConv(conv);
    setMessages(conv.messages);
    setMobileView("chat");
    // mark as read
    setConversations(prev => prev.map(c =>
      c.id === conv.id ? { ...c, unread: 0 } : c
    ));
  };

  /* ── send message ── */
  const sendMessage = (e) => {
    e.preventDefault();
    if (!inputText.trim()) return;

    const newMsg = {
      id: messages.length + 1,
      from: "user",
      text: inputText.trim(),
      time: new Date().toLocaleTimeString([], { hour:"2-digit", minute:"2-digit" }),
      read: false,
    };

    setMessages(prev => [...prev, newMsg]);
    setConversations(prev => prev.map(c =>
      c.id === activeConv.id
        ? { ...c, lastMsg: inputText.trim(), time: "Now" }
        : c
    ));
    setInputText("");
    setShowEmoji(false);
    inputRef.current?.focus();

    // simulate owner reply after 1.5s
    setTimeout(() => {
      const replies = [
        "Sure, I'll check and get back to you!",
        "Thanks for your message. Let me confirm.",
        "That sounds good! When are you available?",
        "Of course! Feel free to visit anytime.",
        "I'll send you the details shortly.",
      ];
      const reply = {
        id: messages.length + 2,
        from: "owner",
        text: replies[Math.floor(Math.random() * replies.length)],
        time: new Date().toLocaleTimeString([], { hour:"2-digit", minute:"2-digit" }),
        read: false,
      };
      setMessages(prev => [...prev, reply]);
    }, 1500);
  };

  /* ── emoji pick ── */
  const pickEmoji = (emoji) => {
    setInputText(prev => prev + emoji);
    inputRef.current?.focus();
  };

  /* ── filtered conversations ── */
  const filteredConvs = conversations.filter(c =>
    c.userName.toLowerCase().includes(searchQuery.toLowerCase()) ||
    c.property.title.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const totalUnread = conversations.reduce((s, c) => s + c.unread, 0);

  return (
    <div className="ch-root">

      {/* ── NAVBAR ── */}
      <nav className="ch-nav">
        <a href="/" className="ch-logo">RentSpace</a>
        <div className="ch-nav-links">
          <a href="/">Home</a>
          <a href="/listings">Rentals</a>
          <a href="/user-dashboard">Dashboard</a>
          <a href="/login" className="ch-logout">Logout</a>
        </div>
      </nav>

      <div className="ch-body">

        {/* ── CONVERSATIONS SIDEBAR ── */}
        <div className={`ch-sidebar ${mobileView === "chat" ? "ch-hide-mobile" : ""}`}>

          {/* SIDEBAR HEADER */}
          <div className="ch-sidebar-header">
            <div className="ch-sidebar-title">
              <h2>Messages</h2>
              {totalUnread > 0 && (
                <span className="ch-total-unread">{totalUnread}</span>
              )}
            </div>
          </div>

          {/* SEARCH */}
          <div className="ch-search-wrap">
            <FaSearch className="ch-search-icon" />
            <input
              type="text"
              placeholder="Search conversations..."
              value={searchQuery}
              onChange={e => setSearchQuery(e.target.value)}
            />
            {searchQuery && (
              <button className="ch-search-clear" onClick={() => setSearchQuery("")}>
                <FaTimes />
              </button>
            )}
          </div>

          {/* CONVERSATION LIST */}
          <div className="ch-conv-list">
            {filteredConvs.length === 0 ? (
              <div className="ch-no-results">No conversations found</div>
            ) : (
              filteredConvs.map(conv => (
                <div
                  key={conv.id}
                  className={`ch-conv-item ${activeConv?.id === conv.id ? "active" : ""} ${conv.unread > 0 ? "unread" : ""}`}
                  onClick={() => selectConv(conv)}
                >
                  {/* AVATAR */}
                  <div className="ch-conv-avatar">
                    <img src={conv.avatar} alt={conv.userName} />
                    {conv.online && <span className="ch-online-dot" />}
                  </div>

                  {/* INFO */}
                  <div className="ch-conv-info">
                    <div className="ch-conv-top">
                      <h4>{conv.userName}</h4>
                      <span className="ch-conv-time">{conv.time}</span>
                    </div>
                    <p className="ch-conv-property">{conv.property.title}</p>
                    <p className={`ch-conv-last ${conv.unread > 0 ? "bold" : ""}`}>
                      {conv.lastMsg}
                    </p>
                  </div>

                  {/* UNREAD */}
                  {conv.unread > 0 && (
                    <span className="ch-unread-badge">{conv.unread}</span>
                  )}
                </div>
              ))
            )}
          </div>
        </div>

        {/* ── CHAT WINDOW ── */}
        <div className={`ch-chat ${mobileView === "list" ? "ch-hide-mobile" : ""}`}>

          {activeConv ? (
            <>
              {/* CHAT HEADER */}
              <div className="ch-chat-header">
                <button className="ch-back-btn" onClick={() => setMobileView("list")}>
                  <FaArrowLeft />
                </button>
                <div className="ch-chat-user">
                  <div className="ch-chat-avatar">
                    <img src={activeConv.avatar} alt={activeConv.userName} />
                    {activeConv.online && <span className="ch-online-dot" />}
                  </div>
                  <div>
                    <h4>{activeConv.userName}</h4>
                    <p className={activeConv.online ? "ch-status-online" : "ch-status-offline"}>
                      <FaCircle /> {activeConv.online ? "Online" : "Last seen recently"}
                    </p>
                  </div>
                </div>
                <div className="ch-chat-actions">
                  <button className="ch-action-btn" title="Call"><FaPhone /></button>
                  <button className="ch-action-btn" title="Video"><FaVideo /></button>
                  <button
                    className={`ch-action-btn ${showProperty ? "active" : ""}`}
                    title="Property Info"
                    onClick={() => setShowProperty(s => !s)}
                  >
                    <FaHome />
                  </button>
                  <button className="ch-action-btn" title="More"><FaEllipsisV /></button>
                </div>
              </div>

              {/* CHAT BODY */}
              <div className="ch-chat-body">

                {/* MESSAGES */}
                <div className="ch-messages">

                  {/* DATE SEPARATOR */}
                  <div className="ch-date-sep">
                    <span>Today</span>
                  </div>

                  {messages.map((msg, idx) => {
                    const isUser  = msg.from === "user";
                    const showAvatar = !isUser && (idx === 0 || messages[idx-1].from !== "owner");
                    return (
                      <div
                        key={msg.id}
                        className={`ch-msg-row ${isUser ? "ch-msg-user" : "ch-msg-owner"}`}
                      >
                        {!isUser && (
                          <div className="ch-msg-avatar">
                            {showAvatar
                              ? <img src={activeConv.avatar} alt={activeConv.userName} />
                              : <div className="ch-avatar-spacer" />
                            }
                          </div>
                        )}
                        <div className={`ch-bubble ${isUser ? "ch-bubble-user" : "ch-bubble-owner"}`}>
                          <p>{msg.text}</p>
                          <div className="ch-bubble-meta">
                            <span>{msg.time}</span>
                            {isUser && (
                              msg.read
                                ? <FaCheckDouble className="ch-read-icon read" />
                                : <FaCheck className="ch-read-icon" />
                            )}
                          </div>
                        </div>
                      </div>
                    );
                  })}
                  <div ref={messagesEndRef} />
                </div>

                {/* EMOJI PICKER */}
                {showEmoji && (
                  <div className="ch-emoji-picker">
                    {EMOJIS.map(e => (
                      <button key={e} onClick={() => pickEmoji(e)}>{e}</button>
                    ))}
                  </div>
                )}

                {/* INPUT */}
                <form className="ch-input-bar" onSubmit={sendMessage}>
                  <button
                    type="button"
                    className={`ch-input-action ${showEmoji ? "active" : ""}`}
                    onClick={() => setShowEmoji(s => !s)}
                  >
                    <FaSmile />
                  </button>
                  <button type="button" className="ch-input-action">
                    <FaPaperclip />
                  </button>
                  <input
                    ref={inputRef}
                    type="text"
                    placeholder={`Message ${activeConv.userName}...`}
                    value={inputText}
                    onChange={e => setInputText(e.target.value)}
                    onKeyDown={e => e.key === "Enter" && !e.shiftKey && sendMessage(e)}
                  />
                  <button
                    type="submit"
                    className={`ch-send-btn ${inputText.trim() ? "active" : ""}`}
                    disabled={!inputText.trim()}
                  >
                    <FaPaperPlane />
                  </button>
                </form>
              </div>
            </>
          ) : (
            <div className="ch-empty-chat">
              <FaHome />
              <h3>Select a conversation</h3>
              <p>Choose a chat from the left to start messaging</p>
            </div>
          )}
        </div>

        {/* ── PROPERTY INFO PANEL ── */}
        {showProperty && activeConv && (
          <div className="ch-property-panel">
            <div className="ch-pp-header">
              <h3>Property Info</h3>
              <button onClick={() => setShowProperty(false)}><FaTimes /></button>
            </div>
            <div className="ch-pp-content">
              <img src={activeConv.property.image} alt={activeConv.property.title} />
              <h4>{activeConv.property.title}</h4>
              <p className="ch-pp-loc">
                <FaMapMarkerAlt /> {activeConv.property.location}, Coimbatore
              </p>
              <div className="ch-pp-meta">
                <span><FaBed /> {activeConv.property.beds} Beds</span>
                <span><FaBath /> {activeConv.property.baths} Baths</span>
              </div>
              <p className="ch-pp-price">
                ₹{activeConv.property.price.toLocaleString()}<span>/mo</span>
              </p>
              <a href={`/property/${activeConv.property.id}`} className="ch-pp-view-btn">
                View Property <FaExternalLinkAlt />
              </a>
              <a href="/booking" className="ch-pp-book-btn">
                Book Now
              </a>
            </div>
          </div>
        )}

      </div>
    </div>
  );
}
